<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Kanban Board</title>
<style>
  * { margin: 0; padding: 0; box-sizing: border-box; }

  :root {
    --bg: #eef1f6;
    --col-bg: #f6f8fb;
    --card-bg: #ffffff;
    --text: #1e293b;
    --muted: #64748b;
    --accent: #4f46e5;
    --accent-hover: #4338ca;
    --todo: #3b82f6;
    --doing: #f59e0b;
    --done: #22c55e;
    --danger: #ef4444;
  }

  body {
    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif;
    background: linear-gradient(135deg, #eef1f6 0%, #e4e9f2 100%);
    min-height: 100vh;
    color: var(--text);
    padding: 24px;
  }

  .topbar {
    max-width: 1100px;
    margin: 0 auto 24px auto;
    display: flex;
    flex-wrap: wrap;
    align-items: center;
    gap: 16px;
    justify-content: space-between;
  }

  .topbar h1 {
    font-size: 26px;
    font-weight: 800;
    letter-spacing: -0.5px;
    display: flex;
    align-items: center;
    gap: 10px;
  }

  .topbar h1::before {
    content: "";
    width: 14px;
    height: 14px;
    border-radius: 4px;
    background: linear-gradient(135deg, var(--accent), #818cf8);
    box-shadow: 0 2px 6px rgba(79, 70, 229, 0.4);
  }

  .add-bar {
    display: flex;
    gap: 10px;
    flex: 1;
    max-width: 480px;
    min-width: 260px;
  }

  #new-card {
    flex: 1;
    padding: 11px 14px;
    font-size: 14px;
    border: 1px solid #d6dce6;
    border-radius: 10px;
    background: #fff;
    color: var(--text);
    outline: none;
    transition: border-color 0.15s, box-shadow 0.15s;
  }

  #new-card:focus {
    border-color: var(--accent);
    box-shadow: 0 0 0 3px rgba(79, 70, 229, 0.15);
  }

  #add-card {
    padding: 11px 20px;
    font-size: 14px;
    font-weight: 600;
    color: #fff;
    background: var(--accent);
    border: none;
    border-radius: 10px;
    cursor: pointer;
    transition: background 0.15s, transform 0.1s, box-shadow 0.15s;
    box-shadow: 0 2px 8px rgba(79, 70, 229, 0.3);
    white-space: nowrap;
  }

  #add-card:hover { background: var(--accent-hover); }
  #add-card:active { transform: scale(0.97); }

  .board {
    max-width: 1100px;
    margin: 0 auto;
    display: grid;
    grid-template-columns: repeat(3, 1fr);
    gap: 20px;
    align-items: start;
  }

  .column {
    background: var(--col-bg);
    border: 1px solid #e2e8f0;
    border-radius: 14px;
    padding: 16px;
    min-height: 320px;
    display: flex;
    flex-direction: column;
    transition: background 0.15s, border-color 0.15s, box-shadow 0.15s;
  }

  .column.drag-over {
    background: #eef2ff;
    border-color: var(--accent);
    box-shadow: 0 0 0 3px rgba(79, 70, 229, 0.12);
  }

  .col-header {
    display: flex;
    align-items: center;
    gap: 8px;
    margin-bottom: 14px;
    padding: 0 2px;
  }

  .col-header .dot {
    width: 9px;
    height: 9px;
    border-radius: 50%;
    flex-shrink: 0;
  }

  #col-todo  .dot { background: var(--todo);  box-shadow: 0 0 6px rgba(59,130,246,0.6); }
  #col-doing .dot { background: var(--doing); box-shadow: 0 0 6px rgba(245,158,11,0.6); }
  #col-done  .dot { background: var(--done);  box-shadow: 0 0 6px rgba(34,197,94,0.6); }

  .col-header h2 {
    font-size: 14px;
    font-weight: 700;
    text-transform: uppercase;
    letter-spacing: 0.6px;
    color: var(--muted);
  }

  .count {
    margin-left: auto;
    background: #e2e8f0;
    color: var(--muted);
    font-size: 12px;
    font-weight: 700;
    min-width: 24px;
    height: 24px;
    padding: 0 8px;
    border-radius: 12px;
    display: inline-flex;
    align-items: center;
    justify-content: center;
  }

  .cards {
    display: flex;
    flex-direction: column;
    gap: 10px;
    flex: 1;
    min-height: 60px;
  }

  .card {
    background: var(--card-bg);
    border: 1px solid #e8edf3;
    border-radius: 10px;
    padding: 12px 14px;
    display: flex;
    align-items: flex-start;
    justify-content: space-between;
    gap: 10px;
    box-shadow: 0 1px 3px rgba(15, 23, 42, 0.08);
    cursor: grab;
    transition: box-shadow 0.15s, transform 0.15s, opacity 0.15s;
    word-break: break-word;
  }

  .card:hover {
    box-shadow: 0 4px 12px rgba(15, 23, 42, 0.14);
    transform: translateY(-1px);
  }

  .card:active { cursor: grabbing; }

  .card.dragging {
    opacity: 0.45;
    transform: rotate(1.5deg) scale(0.98);
    box-shadow: 0 8px 20px rgba(15, 23, 42, 0.2);
  }

  .card-title {
    font-size: 14px;
    line-height: 1.45;
    flex: 1;
  }

  .card-del {
    border: none;
    background: transparent;
    color: #94a3b8;
    font-size: 18px;
    line-height: 1;
    width: 24px;
    height: 24px;
    border-radius: 6px;
    cursor: pointer;
    flex-shrink: 0;
    display: inline-flex;
    align-items: center;
    justify-content: center;
    transition: background 0.15s, color 0.15s;
  }

  .card-del:hover {
    background: rgba(239, 68, 68, 0.12);
    color: var(--danger);
  }

  @media (max-width: 820px) {
    .board { grid-template-columns: 1fr; }
    .column { min-height: 180px; }
  }
</style>
</head>
<body>

  <div class="topbar">
    <h1>Kanban Board</h1>
    <div class="add-bar">
      <input id="new-card" type="text" placeholder="Enter a card title…" autocomplete="off" />
      <button id="add-card" type="button">+ Add Card</button>
    </div>
  </div>

  <main class="board">
    <section class="column" id="col-todo">
      <header class="col-header">
        <span class="dot"></span>
        <h2>To Do</h2>
        <span class="count">0</span>
      </header>
      <div class="cards"></div>
    </section>

    <section class="column" id="col-doing">
      <header class="col-header">
        <span class="dot"></span>
        <h2>Doing</h2>
        <span class="count">0</span>
      </header>
      <div class="cards"></div>
    </section>

    <section class="column" id="col-done">
      <header class="col-header">
        <span class="dot"></span>
        <h2>Done</h2>
        <span class="count">0</span>
      </header>
      <div class="cards"></div>
    </section>
  </main>

<script>
(function () {
  "use strict";

  var STORAGE_KEY = "kanban-board-state";
  var input = document.getElementById("new-card");
  var addBtn = document.getElementById("add-card");
  var columns = Array.prototype.slice.call(document.querySelectorAll(".column"));
  var draggedCard = null;

  function updateCounts() {
    columns.forEach(function (col) {
      col.querySelector(".count").textContent =
        col.querySelectorAll(".card").length;
    });
  }

  function save() {
    var state = {};
    columns.forEach(function (col) {
      state[col.id] = Array.prototype.map.call(
        col.querySelectorAll(".card"),
        function (card) {
          return card.querySelector(".card-title").textContent;
        }
      );
    });
    try {
      localStorage.setItem(STORAGE_KEY, JSON.stringify(state));
    } catch (e) { /* storage unavailable — board still works in-memory */ }
  }

  function createCard(title) {
    var card = document.createElement("div");
    card.className = "card";
    card.draggable = true;

    var titleEl = document.createElement("span");
    titleEl.className = "card-title";
    titleEl.textContent = title;

    var del = document.createElement("button");
    del.className = "card-del";
    del.type = "button";
    del.innerHTML = "&times;";
    del.title = "Delete card";
    del.setAttribute("aria-label", "Delete card");
    del.addEventListener("click", function (e) {
      e.stopPropagation();
      card.remove();
      updateCounts();
      save();
    });

    card.appendChild(titleEl);
    card.appendChild(del);

    card.addEventListener("dragstart", function (e) {
      draggedCard = card;
      e.dataTransfer.effectAllowed = "move";
      try { e.dataTransfer.setData("text/plain", title); } catch (err) {}
      setTimeout(function () { card.classList.add("dragging"); }, 0);
    });

    card.addEventListener("dragend", function () {
      card.classList.remove("dragging");
      draggedCard = null;
      columns.forEach(function (c) { c.classList.remove("drag-over"); });
      updateCounts();
      save();
    });

    return card;
  }

  function addCard() {
    var text = input.value.trim();
    if (!text) return;
    var card = createCard(text);
    document.querySelector("#col-todo .cards").appendChild(card);
    input.value = "";
    input.focus();
    updateCounts();
    save();
  }

  addBtn.addEventListener("click", addCard);
  input.addEventListener("keydown", function (e) {
    if (e.key === "Enter") addCard();
  });

  function getAfterElement(container, y) {
    var els = Array.prototype.slice.call(
      container.querySelectorAll(".card:not(.dragging)")
    );
    var closest = { offset: -Infinity, element: null };
    els.forEach(function (child) {
      var box = child.getBoundingClientRect();
      var offset = y - box.top - box.height / 2;
      if (offset < 0 && offset > closest.offset) {
        closest = { offset: offset, element: child };
      }
    });
    return closest.element;
  }

  columns.forEach(function (col) {
    var container = col.querySelector(".cards");

    col.addEventListener("dragover", function (e) {
      e.preventDefault();
      e.dataTransfer.dropEffect = "move";
      col.classList.add("drag-over");
      if (draggedCard) {
        var after = getAfterElement(container, e.clientY);
        if (after === null) container.appendChild(draggedCard);
        else container.insertBefore(draggedCard, after);
      }
    });

    col.addEventListener("dragleave", function (e) {
      if (!col.contains(e.relatedTarget)) col.classList.remove("drag-over");
    });

    col.addEventListener("drop", function (e) {
      e.preventDefault();
      col.classList.remove("drag-over");
      if (draggedCard) {
        var after = getAfterElement(container, e.clientY);
        if (after === null) container.appendChild(draggedCard);
        else container.insertBefore(draggedCard, after);
        updateCounts();
        save();
      }
    });
  });

  function load() {
    var state = null;
    try {
      state = JSON.parse(localStorage.getItem(STORAGE_KEY));
    } catch (e) { state = null; }
    if (!state || typeof state !== "object") return;
    columns.forEach(function (col) {
      var list = state[col.id];
      if (Array.isArray(list)) {
        var container = col.querySelector(".cards");
        list.forEach(function (t) {
          container.appendChild(createCard(String(t)));
        });
      }
    });
  }

  load();
  updateCounts();
})();
</script>
</body>
</html>
